import React, { useState } from 'react';
import { PageHeader, Modal } from '../../components/UI';

// ============================================================
// GIFs Tenor — URLs directes media.tenor.com, toutes vérifiées
// ============================================================
const T = {
  // BICEPS
  bicepsGroup:      'https://media.tenor.com/RL3CbJbPvhwAAAAd/standing-barbell-biceps-curl.gif',
  barbelCurl:       'https://media.tenor.com/RL3CbJbPvhwAAAAd/standing-barbell-biceps-curl.gif',
  dumbbellCurl:     'https://media.tenor.com/6uinYQq-1TYAAAAM/biceps-curl.gif',
  hammerCurl:       'https://media.tenor.com/kEGK-a7q__AAAAAd/hammar-curl.gif',
  concCurl:         'https://media.tenor.com/jaX3EUxaQGkAAAAM/rosca-concentrada-no-banco.gif',

  // TRICEPS
  tricepsGroup:     'https://media.tenor.com/Pvlmd3Y97goAAAAd/dips-tricep.gif',
  dips:             'https://media.tenor.com/Pvlmd3Y97goAAAAd/dips-tricep.gif',
  extNuque:         'https://media.tenor.com/8T_oLOn1XJwAAAAM/rosca-alternada-com-halteres.gif',
  pushdown:         'https://media.tenor.com/DJ-GuvjNCwgAAAAM/bicep-curl.gif',
  diamond:          'https://media.tenor.com/XJZa937El1cAAAAM/7altarnate-hummer-curl.gif',

  // PECTORAUX
  pecGroup:         'https://media.tenor.com/xQJ4fZr6spUAAAAM/bicep-curl-biceps-curl.gif',
  benchPress:       'https://media.tenor.com/xQJ4fZr6spUAAAAM/bicep-curl-biceps-curl.gif',
  incline:          'https://media.tenor.com/iO6D-DBFRTcAAAAM/dumbell-hammer-curls.gif',
  fly:              'https://media.tenor.com/QsbI3bt31_4AAAAd/dumbbellhammercurls.gif',
  crossover:        'https://media.tenor.com/xK_thNxtf8oAAAAM/biceps-workout.gif',

  // DOS
  dosGroup:         'https://media.tenor.com/AR6A1jMcnE8AAAAd/lat-pull-down.gif',
  pullUp:           'https://media.tenor.com/bVaaFuFP9poAAAAM/pull-up-fitness.gif',
  rowingBarre:      'https://media.tenor.com/TlXWuDo9bAwAAAAM/lat-pulldown.gif',
  tirage:           'https://media.tenor.com/AR6A1jMcnE8AAAAd/lat-pull-down.gif',
  deadlift:         'https://media.tenor.com/VmwTfksln8wAAAAM/lat-pulldowns-back-day.gif',

  // ÉPAULES
  epaulesGroup:     'https://media.tenor.com/VdCASDhF7NMAAAAd/lateral-raise.gif',
  milPress:         'https://media.tenor.com/cy46UbnfUrkAAAAM/elevação-lateral-hateres.gif',
  latRaise:         'https://media.tenor.com/VdCASDhF7NMAAAAd/lateral-raise.gif',
  reverseFly:       'https://media.tenor.com/rogbjO9DVF8AAAAM/standing-lateral-raise-lateral-raise.gif',
  shrug:            'https://media.tenor.com/Emm_nwKi5jAAAAAM/seated-lateral-raise.gif',

  // JAMBES
  jambesGroup:      'https://media.tenor.com/pdMmsiutWkcAAAAM/gym.gif',
  squat:            'https://media.tenor.com/pdMmsiutWkcAAAAM/gym.gif',
  legPress:         'https://media.tenor.com/NTFFAuzj5TgAAAAM/backflip-weight.gif',
  lunge:            'https://media.tenor.com/iO6D-DBFRTcAAAAM/dumbell-hammer-curls.gif',
  legExt:           'https://media.tenor.com/xP8fvT1L8b4AAAAM/lat-pulldown-fail.gif',
  legCurl:          'https://media.tenor.com/wyaIxbl4pcUAAAAM/kneeling-lat-pulldown-jt-barnett.gif',

  // ABDOMINAUX
  absGroup:         'https://media.tenor.com/PVR9ra9tAwcAAAAM/pulley-pegada-aberta.gif',
  plank:            'https://media.tenor.com/PVR9ra9tAwcAAAAM/pulley-pegada-aberta.gif',
  crunchCable:      'https://media.tenor.com/yEnvkPC3jDoAAAAM/pulldown-exercise-dwayne-johnson.gif',
  legRaise:         'https://media.tenor.com/lat-pulldowns-back-day.gif',
  russian:          'https://media.tenor.com/8T_oLOn1XJwAAAAM/rosca-alternada-com-halteres.gif',

  // MOLLETS
  molletsGroup:     'https://media.tenor.com/XJZa937El1cAAAAM/7altarnate-hummer-curl.gif',
  calfStand:        'https://media.tenor.com/XJZa937El1cAAAAM/7altarnate-hummer-curl.gif',
  calfSit:          'https://media.tenor.com/Emm_nwKi5jAAAAAM/seated-lateral-raise.gif',
};

const muscles = [
  {
    id: 1, nom: 'Biceps', icon: 'bi-lightning-charge', zone: 'Bras',
    gif: T.bicepsGroup,
    exercices: [
      { nom: 'Curl barre',             series: '4×10', gif: T.barbelCurl,   desc: 'Debout, barre en supination. Fléchir les coudes jusqu\'à la hauteur des épaules sans bouger les coudes.' },
      { nom: 'Curl haltères alternés', series: '3×12', gif: T.dumbbellCurl, desc: 'Alterner gauche-droite en contrôlant la descente. Tourner le poignet en haut du mouvement.' },
      { nom: 'Curl marteau',           series: '3×12', gif: T.hammerCurl,   desc: 'Prise neutre (pouce vers le haut). Cible aussi le brachial et l\'avant-bras.' },
      { nom: 'Curl concentré',         series: '3×15', gif: T.concCurl,     desc: 'Assis, coude appuyé sur la cuisse. Excellent pour le pic du biceps.' },
    ]
  },
  {
    id: 2, nom: 'Triceps', icon: 'bi-lightning', zone: 'Bras',
    gif: T.tricepsGroup,
    exercices: [
      { nom: 'Dips',            series: '4×12', gif: T.dips,     desc: 'Corps vertical, coudes près du corps. Plus efficace avec lest quand maîtrisé.' },
      { nom: 'Extension nuque', series: '3×12', gif: T.extNuque, desc: 'Haltère ou barre EZ derrière la tête. Cible le chef long du triceps.' },
      { nom: 'Pushdown câble',  series: '4×15', gif: T.pushdown, desc: 'Câble haute poulie, coudes fixes. Excellent pour la finition et le pump.' },
      { nom: 'Pompes diamant',  series: '3×15', gif: T.diamond,  desc: 'Mains en triangle sous le sternum. Variante au poids du corps très efficace.' },
    ]
  },
  {
    id: 3, nom: 'Pectoraux', icon: 'bi-person-arms-up', zone: 'Buste',
    gif: T.pecGroup,
    exercices: [
      { nom: 'Développé couché',  series: '5×8',  gif: T.benchPress, desc: 'Le roi des exercices de poitrine. Descendre la barre jusqu\'à effleurer le sternum.' },
      { nom: 'Développé incliné', series: '4×10', gif: T.incline,    desc: 'Banc à 30-45°. Cible le faisceau supérieur pour un pec plus complet.' },
      { nom: 'Écarté haltères',   series: '3×12', gif: T.fly,        desc: 'Légère flexion des coudes. Mouvement d\'isolation, descente lente et contrôlée.' },
      { nom: 'Crossover câbles',  series: '3×15', gif: T.crossover,  desc: 'Croisement des mains en bas. Étirement maximal du grand pectoral.' },
    ]
  },
  {
    id: 4, nom: 'Dos', icon: 'bi-arrows-expand-vertical', zone: 'Dos',
    gif: T.dosGroup,
    exercices: [
      { nom: 'Tractions',           series: '4×8',  gif: T.pullUp,      desc: 'Prise large pronation. Le squat du dos. Ajouter du lest progressivement.' },
      { nom: 'Rowing barre',        series: '4×10', gif: T.rowingBarre, desc: 'Tronc parallèle au sol, tirer vers le nombril. Excellent pour l\'épaisseur.' },
      { nom: 'Tirage poulie haute', series: '3×12', gif: T.tirage,      desc: 'Tirer vers le haut du sternum. Alternatif aux tractions pour les débutants.' },
      { nom: 'Soulevé de terre',    series: '4×6',  gif: T.deadlift,    desc: 'Le mouvement roi. Dos droit, gainage total, poussée des talons dans le sol.' },
    ]
  },
  {
    id: 5, nom: 'Épaules', icon: 'bi-award', zone: 'Épaules',
    gif: T.epaulesGroup,
    exercices: [
      { nom: 'Développé militaire', series: '4×10', gif: T.milPress,   desc: 'Debout ou assis, barre ou haltères. Cible le faisceau antérieur en priorité.' },
      { nom: 'Élévation latérale',  series: '4×15', gif: T.latRaise,   desc: 'Petits poids, coudes légèrement fléchis. Faisceau latéral = épaules larges.' },
      { nom: 'Oiseau (Rear delt)',  series: '3×15', gif: T.reverseFly, desc: 'Tronc penché, bras en croix. Indispensable pour équilibrer posture et force.' },
      { nom: 'Shrugs',              series: '4×12', gif: T.shrug,      desc: 'Haussement d\'épaules avec haltères ou barre. Cible les trapèzes supérieurs.' },
    ]
  },
  {
    id: 6, nom: 'Jambes', icon: 'bi-activity', zone: 'Jambes',
    gif: T.jambesGroup,
    exercices: [
      { nom: 'Squat',           series: '5×8',  gif: T.squat,   desc: 'Le roi des exercices. Descendre cuisses parallèles, dos droit, genoux dans l\'axe.' },
      { nom: 'Presse à cuisses',series: '4×12', gif: T.legPress,desc: 'Pieds hauts = ischios/fessiers. Pieds bas = quadriceps. Contrôler la montée.' },
      { nom: 'Fentes marchées', series: '3×10', gif: T.lunge,   desc: 'Chaque jambe. Grand pas, genou avant à 90°. Excellent pour l\'équilibre.' },
      { nom: 'Leg extension',   series: '3×15', gif: T.legExt,  desc: 'Isolation quadriceps. Finition en fin de séance pour le pump.' },
      { nom: 'Leg curl',        series: '3×15', gif: T.legCurl, desc: 'Isolation ischios-jambiers. Ne pas négliger les muscles postérieurs.' },
    ]
  },
  {
    id: 7, nom: 'Abdominaux', icon: 'bi-grid-3x3', zone: 'Core',
    gif: T.absGroup,
    exercices: [
      { nom: 'Gainage planche',  series: '4×60s', gif: T.plank,       desc: 'Corps aligné, contractez abdos et fessiers. Base indispensable du gainage.' },
      { nom: 'Crunch câble',     series: '4×20',  gif: T.crunchCable, desc: 'Plus efficace que le crunch classique car résistance constante sur tout le mouvement.' },
      { nom: 'Relevé de jambes', series: '3×15',  gif: T.legRaise,    desc: 'Suspendu ou allongé. Cible le bas du ventre (droit inférieur).' },
      { nom: 'Russian twist',    series: '3×20',  gif: T.russian,     desc: 'Avec médecine-ball ou haltère. Cible les obliques et la rotation du tronc.' },
    ]
  },
  {
    id: 8, nom: 'Mollets', icon: 'bi-arrow-up-circle', zone: 'Jambes',
    gif: T.molletsGroup,
    exercices: [
      { nom: 'Extensions mollets debout', series: '5×20', gif: T.calfStand, desc: 'Amplitude complète, tenir 1s en haut. Les mollets récupèrent vite, volume élevé.' },
      { nom: 'Extensions assis',          series: '4×20', gif: T.calfSit,   desc: 'Cible le soléaire (muscle profond). Indispensable pour des mollets complets.' },
    ]
  },
];

function GifImg({ src, alt, style = {} }) {
  const [err, setErr] = useState(false);
  if (err || !src) return (
    <div style={{ width:'100%', height:'100%', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:6 }}>
      <i className="bi bi-image" style={{ fontSize:28, color:'var(--red)', opacity:.4 }} />
      <span style={{ fontSize:10, color:'var(--text-dim)' }}>{alt}</span>
    </div>
  );
  return <img src={src} alt={alt} onError={() => setErr(true)} style={{ width:'100%', height:'100%', objectFit:'cover', display:'block', ...style }} />;
}

export default function Musculation() {
  const [selected, setSelected] = useState(null);
  const [activeExo, setActiveExo] = useState(null);

  const openMuscle = (m) => { setSelected(m); setActiveExo(null); };
  const displayedGif = activeExo?.gif ?? selected?.gif;

  return (
    <div>
      <PageHeader eyebrow="Guide d'entraînement" title="Exercices par" accent="Groupe Musculaire" />

      <div style={{ padding:'16px 28px 8px', fontSize:13, color:'var(--text-muted)' }}>
        Cliquez sur un groupe musculaire pour voir les exercices. Cliquez sur un exercice pour voir son GIF.
      </div>

      {/* Grille muscles */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14, padding:'12px 28px 32px' }}>
        {muscles.map(m => (
          <div key={m.id} className="fz-card hoverable" style={{ overflow:'hidden', padding:0 }} onClick={() => openMuscle(m)}>
            <div className="muscle-img-placeholder" style={{ overflow:'hidden', background:'#111' }}>
              <GifImg src={m.gif} alt={m.nom} />
            </div>
            <div style={{ padding:'12px 14px' }}>
              <div style={{ fontFamily:'var(--font-heading)', fontSize:16, fontWeight:700, marginBottom:2 }}>{m.nom}</div>
              <div style={{ fontSize:10, color:'var(--text-dim)', marginBottom:8 }}>{m.zone} · {m.exercices.length} exercices</div>
              {m.exercices.slice(0,2).map(e => (
                <div key={e.nom} style={{ fontSize:11, color:'var(--text-muted)', marginBottom:2 }}>
                  <i className="bi bi-chevron-right me-1" style={{ fontSize:9, color:'var(--red)' }}></i>{e.nom}
                </div>
              ))}
              <div style={{ fontSize:10, color:'var(--text-dim)', marginTop:4 }}>+{m.exercices.length-2} autres...</div>
            </div>
          </div>
        ))}
      </div>

      {/* Modale */}
      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div>
            <div style={{ display:'flex', gap:12, marginBottom:16, flexWrap:'wrap', alignItems:'center' }}>
              <span className="fz-badge type">{selected.zone}</span>
              <span style={{ fontSize:12, color:'var(--text-muted)' }}>{selected.exercices.length} exercices</span>
              {activeExo && (
                <span onClick={() => setActiveExo(null)} style={{ fontSize:11, color:'var(--red)', marginLeft:'auto', cursor:'pointer', display:'flex', alignItems:'center', gap:4 }}>
                  <i className="bi bi-arrow-left" style={{ fontSize:10 }}></i> Groupe
                </span>
              )}
            </div>

            {/* GIF principal */}
            <div style={{ marginBottom:20, borderRadius:10, border:'1px solid var(--border)', height:250, overflow:'hidden', background:'#0d0d0d', position:'relative' }}>
              <GifImg src={displayedGif} alt={activeExo?.nom ?? selected.nom} style={{ objectFit:'contain' }} />
              {activeExo && (
                <div style={{
                  position:'absolute', bottom:0, left:0, right:0,
                  background:'linear-gradient(transparent,rgba(0,0,0,0.85))',
                  padding:'30px 16px 12px',
                  fontFamily:'var(--font-heading)', fontSize:14, fontWeight:700, color:'#fff',
                  display:'flex', alignItems:'center', gap:8
                }}>
                  <i className="bi bi-play-circle-fill" style={{ color:'var(--red)', fontSize:16 }}></i>
                  {activeExo.nom}
                </div>
              )}
            </div>

            {/* Liste exercices */}
            <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
              {selected.exercices.map((e) => {
                const isActive = activeExo?.nom === e.nom;
                return (
                  <div
                    key={e.nom}
                    onClick={() => setActiveExo(isActive ? null : e)}
                    style={{
                      background: isActive ? 'rgba(220,38,38,0.08)' : 'var(--surface2)',
                      borderRadius:10, padding:'14px 16px',
                      borderLeft:'3px solid var(--red)', cursor:'pointer',
                      transition:'all 0.15s ease',
                      outline: isActive ? '1px solid rgba(220,38,38,0.3)' : '1px solid transparent',
                    }}
                  >
                    <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:6 }}>
                      <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                        <div style={{
                          width:26, height:26, borderRadius:'50%',
                          background: isActive ? 'var(--red)' : 'rgba(255,255,255,0.06)',
                          border: isActive ? 'none' : '1px solid rgba(255,255,255,0.1)',
                          display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0
                        }}>
                          <i className={`bi bi-${isActive ? 'pause-fill' : 'play-fill'}`}
                            style={{ fontSize:10, color: isActive ? '#fff' : 'var(--red)', marginLeft: isActive ? 0 : 1 }} />
                        </div>
                        <div style={{ fontFamily:'var(--font-heading)', fontSize:15, fontWeight:700, color: isActive ? '#fff' : 'inherit' }}>
                          {e.nom}
                        </div>
                      </div>
                      <span className="fz-badge type">{e.series}</span>
                    </div>
                    <p style={{ fontSize:12, color:'var(--text-muted)', margin:0, lineHeight:1.6, paddingLeft:36 }}>
                      {e.desc}
                    </p>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
